.darma-loader-darma-custom-008 {
  width: 50px;
  aspect-ratio: 1.154;
  clip-path: polygon(50% 0, 100% 100%, 0 100%);
  display: grid;
  background: conic-gradient(from 0deg at 50% 60%, #3A89C9 120deg, #0000 0), conic-gradient(from 120deg at 50% 60%, #3A89C9 120deg, #0000 0), conic-gradient(from 240deg at 50% 60%, #3A89C9 120deg, #0000 0), conic-gradient(from 0deg at 50% 60%, #9CC4E4 120deg, #0000 0), conic-gradient(from 120deg at 50% 60%, #9CC4E4 120deg, #0000 0), conic-gradient(from 240deg at 50% 60%, #9CC4E4 120deg, #0000 0), #3A89C9;
  background-size: 200% 200%;
  background-repeat: no-repeat;
  animation: darma-loader-darma-custom-008-l8 1.5s infinite;
}
@keyframes darma-loader-darma-custom-008-l8 {
  0% { background-position: left, top, right; }
  30%, 50% { background-position: left, top, right, center, center, center; }
  80%, 100% { background-position: center; }
}

